# loader.ps1 - Foundation Launcher
param([string]\ = "help")

\.\keys\master.key = "\C:\Workspace_local\workspace-foundation\build\..\keys\master.key"
\ = "\C:\Workspace_local\workspace-foundation\build\protected"

if (-not (Test-Path \.\keys\master.key)) {
    Write-Host "Error: Master key not found. This build is corrupted." -ForegroundColor Red
    exit 1
}

\172 221 213 254 171 209 237 224 167 223 195 173 62 214 46 253 252 66 238 66 214 239 233 145 79 176 71 31 65 34 52 115 = [System.IO.File]::ReadAllBytes(\.\keys\master.key)

\ = "\\scripts\utilities\WF-ORCHESTRATION\wf.ps1.enc"
if (\ -eq "help") { \ = "\\scripts\utilities\foundation-installer-tui.ps1.enc" }

if (-not (Test-Path \)) {
    Write-Host "Error: Encrypted script not found: \" -ForegroundColor Red
    exit 1
}

\ = Get-Content \ -Raw
\ = \ | ConvertTo-SecureString -Key \172 221 213 254 171 209 237 224 167 223 195 173 62 214 46 253 252 66 238 66 214 239 233 145 79 176 71 31 65 34 52 115
\ = \ | ConvertFrom-SecureString

Invoke-Expression \
